// GitHub API 服务 - 用于自动发现组会和上传文件

const REPO_OWNER = "zwy522";
const REPO_NAME = "ABC-group";
const API_BASE = "https://api.github.com";

export interface GitHubContent {
  name: string;
  path: string;
  sha: string;
  size: number;
  url: string;
  html_url: string;
  git_url: string;
  download_url: string | null;
  type: "file" | "dir" | "symlink" | "submodule";
}

export interface MeetingData {
  id: string;
  date: string;
  folderName: string;
  title: string;
  papers: PaperData[];
}

export interface PaperData {
  id: string;
  title: string;
  venue: string;
  presenter: string;
  keywords: string[];
  pdfUrl: string;
  pptxUrls: { label: string; url: string }[];
  mdUrls: { label: string; url: string; repoPath: string }[];
}

function parseFolderDate(folderName: string): string | null {
  const match = folderName.match(/^(\d{4})\.(\d{1,2})\.(\d{1,2})$/);
  if (!match) return null;
  const [, y, m, d] = match;
  return `${y}-${m.padStart(2, "0")}-${d.padStart(2, "0")}`;
}

function extractTitleFromFilename(filename: string): string {
  return filename
    .replace(/\.(pdf|pptx|PPTX|PDF|md|MD)$/i, "")
    .replace(/_PPT$/i, "")
    .replace(/_/g, " ")
    .trim();
}

async function fetchRepoContents(path: string = ""): Promise<GitHubContent[]> {
  const url = `${API_BASE}/repos/${REPO_OWNER}/${REPO_NAME}/contents/${path}?ref=main`;
  const res = await fetch(url);
  if (!res.ok) throw new Error(`Failed to fetch ${path}: ${res.status}`);
  return res.json();
}

// 递归获取仓库所有文件树（单次 API 调用）
async function fetchRepoTreeRecursive(): Promise<{ path: string; type: string }[]> {
  // Step 1: Get the latest commit SHA of main branch
  const refUrl = `${API_BASE}/repos/${REPO_OWNER}/${REPO_NAME}/git/ref/heads/main`;
  const refRes = await fetch(refUrl);
  if (!refRes.ok) throw new Error(`Failed to fetch ref: ${refRes.status}`);
  const refData = await refRes.json();
  const treeSha = refData.object.sha;

  // Step 2: Get the tree recursively (one call for the whole repo)
  const treeUrl = `${API_BASE}/repos/${REPO_OWNER}/${REPO_NAME}/git/trees/${treeSha}?recursive=1`;
  const treeRes = await fetch(treeUrl);
  if (!treeRes.ok) throw new Error(`Failed to fetch tree: ${treeRes.status}`);
  const treeData = await treeRes.json();

  return treeData.tree ?? [];
}

function getRawUrl(path: string): string {
  return `https://github.com/${REPO_OWNER}/${REPO_NAME}/raw/main/${encodeURIComponent(path).replace(/%2F/g, '/')}`;
}

function getContentApiUrl(path: string): string {
  return `${API_BASE}/repos/${REPO_OWNER}/${REPO_NAME}/contents/${encodeURIComponent(path)}`;
}

export async function fetchFileContent(repoPath: string): Promise<string> {
  const url = getContentApiUrl(repoPath);
  const res = await fetch(url);
  if (!res.ok) throw new Error(`Failed to fetch file: ${res.status}`);
  const json = await res.json();
  if (json.content && json.encoding === "base64") {
    const raw = atob(json.content.replace(/\n/g, ""));
    const bytes = Uint8Array.from(raw, (c) => c.charCodeAt(0));
    return new TextDecoder("utf-8").decode(bytes);
  }
  throw new Error("Unexpected API response format");
}

export async function discoverMeetings(): Promise<MeetingData[]> {
  try {
    const tree = await fetchRepoTreeRecursive();

    // 只保留文件（blob），按父目录分组
    const folderFiles = new Map<string, { path: string; name: string }[]>();
    for (const item of tree) {
      if (item.type !== "blob") continue;
      const parts = item.path.split("/");
      if (parts.length !== 2) continue;
      const [folder, filename] = parts;
      const date = parseFolderDate(folder);
      if (!date) continue;
      if (!folderFiles.has(folder)) folderFiles.set(folder, []);
      folderFiles.get(folder)!.push({ path: item.path, name: filename });
    }

    const sortedFolders = [...folderFiles.entries()].sort(
      (a, b) => new Date(parseFolderDate(b[0])!).getTime() - new Date(parseFolderDate(a[0])!).getTime()
    );

    const meetings: MeetingData[] = [];
    let idx = sortedFolders.length;

    for (const [folder, files] of sortedFolders) {
      const date = parseFolderDate(folder)!;
      const pdfFiles = files.filter((f) => f.name.toLowerCase().endsWith(".pdf"));
      const pptxFiles = files.filter((f) => f.name.toLowerCase().endsWith(".pptx"));
      const mdFiles = files.filter((f) => /\.(md|MD)$/.test(f.name));

      const mdEntries = mdFiles.map((f) => ({
        label: extractTitleFromFilename(f.name),
        url: getRawUrl(f.path),
        repoPath: f.path,
      }));

      const papers: PaperData[] = [];

      if (pdfFiles.length > 0) {
        for (const pdf of pdfFiles) {
          papers.push({
            id: `${folder}-${pdf.name}`,
            title: extractTitleFromFilename(pdf.name),
            venue: "",
            presenter: "",
            keywords: [],
            pdfUrl: getRawUrl(pdf.path),
            pptxUrls: pptxFiles.map((p) => ({
              label: extractTitleFromFilename(p.name),
              url: getRawUrl(p.path),
            })),
            mdUrls: mdEntries,
          });
        }
      } else {
        for (const pptx of pptxFiles) {
          papers.push({
            id: `${folder}-${pptx.name}`,
            title: extractTitleFromFilename(pptx.name),
            venue: "",
            presenter: "",
            keywords: [],
            pdfUrl: "",
            pptxUrls: [{ label: extractTitleFromFilename(pptx.name), url: getRawUrl(pptx.path) }],
            mdUrls: mdEntries,
          });
        }
        if (pptxFiles.length === 0 && mdFiles.length > 0) {
          papers.push({
            id: `${folder}-notes`,
            title: extractTitleFromFilename(mdFiles[0].name),
            venue: "",
            presenter: "",
            keywords: [],
            pdfUrl: "",
            pptxUrls: [],
            mdUrls: mdEntries,
          });
        }
      }

      if (papers.length > 0) {
        meetings.push({
          id: folder,
          date,
          folderName: folder,
          title: `第 ${idx} 期组会`,
          papers,
        });
        idx--;
      }
    }

    return meetings;
  } catch (error) {
    console.error("Failed to discover meetings:", error);
    return [];
  }
}

export async function uploadFile(
  token: string,
  path: string,
  content: string,
  message: string
): Promise<{ sha: string; url: string } | null> {
  const url = `${API_BASE}/repos/${REPO_OWNER}/${REPO_NAME}/contents/${path}`;
  const res = await fetch(url, {
    method: "PUT",
    headers: { Authorization: `Bearer ${token}`, "Content-Type": "application/json" },
    body: JSON.stringify({ message, content, branch: "main" }),
  });
  if (!res.ok) { const err = await res.json(); throw new Error(err.message || `Upload failed: ${res.status}`); }
  const data = await res.json();
  return { sha: data.content.sha, url: data.content.html_url };
}

export async function getMeetingsJsonSha(): Promise<string | null> {
  try {
    const res = await fetch(`${API_BASE}/repos/${REPO_OWNER}/${REPO_NAME}/contents/website/src/data/meetings.json`);
    if (!res.ok) return null;
    const data = await res.json();
    return data.sha;
  } catch { return null; }
}

export async function validateToken(token: string): Promise<boolean> {
  const res = await fetch(`${API_BASE}/user`, { headers: { Authorization: `Bearer ${token}` } });
  return res.ok;
}

export function fileToBase64(file: File): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => { const result = reader.result as string; resolve(result.split(",")[1]); };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}
