import { useState } from "react";
import { createPortal } from "react-dom";
import { FileText, Loader2, X, ExternalLink } from "lucide-react";
import { fetchFileContent } from "@/services/github";

function simpleMarkdownToHtml(md: string): string {
  let html = md
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");

  html = html.replace(/```(\w*)\n([\s\S]*?)```/g, (_m, lang, code) => {
    return `<pre class="bg-[#f5f2eb] rounded-lg p-4 overflow-x-auto text-xs my-3 border border-[#e8e4db]"><code>${code.trim()}</code></pre>`;
  });

  html = html.replace(/`([^`]+)`/g, '<code class="bg-[#f5f2eb] px-1.5 py-0.5 rounded text-xs text-[#c96442] font-mono">$1</code>');

  const lines = html.split("\n");
  const result: string[] = [];
  let inList: "ul" | "ol" | null = null;

  for (let i = 0; i < lines.length; i++) {
    let line = lines[i];

    if (/^#{1,6}\s/.test(line)) {
      if (inList) { result.push(`</${inList}>`); inList = null; }
      const level = line.match(/^(#{1,6})/)![1].length;
      const text = line.replace(/^#{1,6}\s*/, "");
      const sizes = ["text-xl", "text-lg", "text-base", "text-sm", "text-xs", "text-xs"];
      result.push(`<h${level} class="font-serif ${sizes[level - 1]} font-semibold text-[#1a1a1a] mt-4 mb-2">${text}</h${level}>`);
      continue;
    }

    const ulMatch = line.match(/^(\s*)[-*+]\s+(.+)/);
    const olMatch = line.match(/^(\s*)\d+\.\s+(.+)/);

    if (ulMatch) {
      if (inList !== "ul") { if (inList) result.push(`</${inList}>`); result.push('<ul class="list-disc list-inside space-y-0.5 text-sm text-[#374151] my-2">'); inList = "ul"; }
      result.push(`<li>${ulMatch[2]}</li>`);
      continue;
    }
    if (olMatch) {
      if (inList !== "ol") { if (inList) result.push(`</${inList}>`); result.push('<ol class="list-decimal list-inside space-y-0.5 text-sm text-[#374151] my-2">'); inList = "ol"; }
      result.push(`<li>${olMatch[2]}</li>`);
      continue;
    }

    if (inList) { result.push(`</${inList}>`); inList = null; }

    if (/^---+$/.test(line.trim())) {
      result.push('<hr class="my-3 border-[#e8e4db]" />');
      continue;
    }

    line = line.replace(/\*\*(.+?)\*\*/g, '<strong class="font-semibold text-[#1a1a1a]">$1</strong>');
    line = line.replace(/\*(.+?)\*/g, '<em>$1</em>');
    line = line.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" target="_blank" rel="noopener noreferrer" class="text-[#c96442] underline hover:text-[#b5573a]">$1</a>');

    if (line.trim() === "") {
      result.push('<div class="h-2"></div>');
    } else {
      result.push(`<p class="text-sm text-[#374151] leading-relaxed">${line}</p>`);
    }
  }

  if (inList) result.push(`</${inList}>`);

  return result.join("\n");
}

interface MarkdownViewerProps {
  title: string;
  url: string;
  filename: string;
  repoPath: string;
}

export default function MarkdownViewer({ title, url, filename, repoPath }: MarkdownViewerProps) {
  const [open, setOpen] = useState(false);
  const [content, setContent] = useState("");
  const [loading, setLoading] = useState(false);
  const [fetched, setFetched] = useState(false);

  const handleToggle = async () => {
    setOpen(!open);
    if (!open && !fetched) {
      setLoading(true);
      try {
        const text = await fetchFileContent(repoPath);
        setContent(simpleMarkdownToHtml(text));
      } catch {
        setContent('<p class="text-red-500">加载失败，请检查网络</p>');
      } finally {
        setLoading(false);
        setFetched(true);
      }
    }
  };

  return (
    <>
      <button
        onClick={handleToggle}
        className="inline-flex items-center gap-1.5 rounded-lg bg-[#f5f2eb] px-3 py-1.5 text-xs font-medium text-[#6b6560] transition-colors hover:bg-[#c96442] hover:text-white"
      >
        <FileText size={14} />
        {open ? "收起笔记" : `阅读笔记`}
      </button>

      {open &&
        createPortal(
          <div
            className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-black/80"
            onClick={() => setOpen(false)}
          >
            <div
              className="relative w-full max-w-2xl max-h-[85vh] overflow-y-auto rounded-2xl bg-white shadow-2xl border border-[#e8e4db]"
              onClick={(e) => e.stopPropagation()}
            >
              <div className="sticky top-0 z-10 flex items-center justify-between bg-white border-b border-[#e8e4db] px-6 py-4 rounded-t-2xl">
                <div>
                  <h2 className="font-serif text-lg font-semibold text-[#1a1a1a]">{title}</h2>
                  <p className="text-xs text-[#9a9590] mt-0.5">{filename}</p>
                </div>
                <div className="flex items-center gap-2">
                  <a
                    href={url}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="inline-flex items-center gap-1 rounded-lg bg-[#f5f2eb] px-3 py-1.5 text-xs font-medium text-[#6b6560] transition-colors hover:bg-[#c96442] hover:text-white"
                  >
                    <ExternalLink size={12} />
                    原始文件
                  </a>
                  <button
                    onClick={() => setOpen(false)}
                    className="p-2 rounded-lg text-[#9a9590] hover:text-[#1a1a1a] hover:bg-[#f5f2eb] transition-colors"
                  >
                    <X size={18} />
                  </button>
                </div>
              </div>
              <div className="px-6 py-5">
                {loading ? (
                  <div className="flex items-center justify-center py-12 text-[#9a9590]">
                    <Loader2 size={24} className="animate-spin" />
                    <span className="ml-2 text-sm">加载中...</span>
                  </div>
                ) : (
                  <div
                    className="prose-custom"
                    dangerouslySetInnerHTML={{ __html: content }}
                  />
                )}
              </div>
            </div>
          </div>,
          document.body
        )}
    </>
  );
}
